code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Statistic } from 'decantr/components';

code.example:
function StatsHero() {
  const { div } = tags;

  return div({ class: css('_py16 _px6 _grid _gc1 _md:gc3 _gap8 _tc d-mesh') },
    Statistic({ label: 'Components', value: 100, suffix: '+', animate: true, class: css('d-gradient-text') }),
    Statistic({ label: 'Bundle Size', value: 12.9, suffix: 'KB', animate: true, class: css('d-gradient-text') }),
    Statistic({ label: 'GitHub Stars', value: 4200, suffix: '+', animate: true, class: css('d-gradient-text') })
  );
}

